Here's a complete example. I'll scaffold the project, then show each file.

**Program.cs** — stdio transport with DI services:

```csharp
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Hosting;
using Microsoft.Extensions.Logging;

var builder = Host.CreateApplicationBuilder(args);
builder.Logging.AddConsole(options =>
    options.LogToStandardErrorThreshold = LogLevel.Trace); // stderr only — stdout is JSON-RPC

builder.Services.AddHttpClient("api", client =>
{
    client.BaseAddress = new Uri("https://jsonplaceholder.typicode.com");
});

builder.Services.AddMcpServer()
    .WithStdioServerTransport()
    .WithToolsFromAssembly();

await builder.Build().RunAsync();
```

**PostTools.cs** — tool class wrapping a REST API:

```csharp
using System.ComponentModel;
using System.Net.Http.Json;
using System.Text.Json.Serialization;
using Microsoft.Extensions.Logging;
using ModelContextProtocol.Server;

[McpServerToolType]
public class PostTools(IHttpClientFactory httpFactory, ILogger<PostTools> logger)
{
    [McpServerTool, Description("Get a blog post by its numeric ID.")]
    public async Task<string> GetPost(
        [Description("The post ID (1-100)")] int id,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Fetching post {Id}", id);
        var client = httpFactory.CreateClient("api");
        var post = await client.GetFromJsonAsync<Post>($"/posts/{id}", cancellationToken);
        return $"Title: {post!.Title}\n\n{post.Body}";
    }

    [McpServerTool, Description("Search posts by user ID.")]
    public async Task<string> GetPostsByUser(
        [Description("The user ID to filter by")] int userId,
        CancellationToken cancellationToken = default)
    {
        var client = httpFactory.CreateClient("api");
        var posts = await client.GetFromJsonAsync<Post[]>(
            $"/posts?userId={userId}", cancellationToken);
        return string.Join("\n", posts!.Select(p => $"[{p.Id}] {p.Title}"));
    }
}

public record Post(
    [property: JsonPropertyName("id")] int Id,
    [property: JsonPropertyName("userId")] int UserId,
    [property: JsonPropertyName("title")] string Title,
    [property: JsonPropertyName("body")] string Body);
```

---

### How DI works for MCP tools

The SDK resolves dependencies **two ways**, and they can be mixed:

| Style | How it works |
|-------|-------------|
| **Constructor injection** (non-static class) | The class is instantiated per-call; DI services go in the primary constructor (e.g. `IHttpClientFactory`, `ILogger<T>`) |
| **Method parameter injection** (static class) | DI services appear as method parameters alongside tool parameters; the SDK tells them apart automatically |

**Key rule:** `CancellationToken`, `IMcpServer`, `IProgress<ProgressNotificationValue>`, and any DI-registered service are **injected automatically** and never appear in the tool's JSON schema that the LLM sees. Only parameters with `[Description]` are exposed to the LLM.

So in `PostTools` above, the LLM sees just `id` / `userId` — it never knows about `IHttpClientFactory` or `ILogger`.

To scaffold this yourself:

```bash
dotnet new mcpserver -n MyApiServer
cd MyApiServer
dotnet add package ModelContextProtocol
dotnet build
```

Then replace the generated files with the code above.
